export function LiveGraph({data, width, height = 100}: {data: number[]; width: number; height?: number}) { const dataSV = useSharedValue(data); React.useEffect(() => { dataSV.value = data; }, [data]); const path = useDerivedValue(() => { const p = Skia.Path.Make(); const d = dataSV.value; if (d.length < 2) return p; const min = Math.min(...d); const max = Math.max(...d); const range = max - min || 1; d.forEach((v, i) => { const x = (i / (d.length - 1)) * width; const y = height - ((v - min) / range) * height; if (i === 0) p.moveTo(x, y); else p.lineTo(x, y); }); return p; }); return (<View style={{width, height}}><Canvas style={StyleSheet.absoluteFill}><Path path={path} style='stroke' strokeWidth={2} color='#FF453A'/></Canvas></View>); }

